package com.trademaster.ims.mobile.fulfillment.controller;
import com.trademaster.ims.mobile.auth.security.CustomerAuthentication;import com.trademaster.ims.mobile.auth.service.CustomerAuthException;import com.trademaster.ims.mobile.fulfillment.dto.FulfillmentDtos.OrderTrackingResponse;import com.trademaster.ims.mobile.fulfillment.service.OrderFulfillmentService;import org.springframework.http.HttpStatus;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/mobile/v1/orders") public class MobileOrderTrackingController{private final OrderFulfillmentService s;public MobileOrderTrackingController(OrderFulfillmentService s){this.s=s;}@GetMapping("/{orderNumber}/tracking")public OrderTrackingResponse tracking(Authentication a,@PathVariable String orderNumber){if(a instanceof CustomerAuthentication c)return s.customerTracking(c.accountId(),orderNumber);throw new CustomerAuthException(HttpStatus.UNAUTHORIZED,"AUTHENTICATION_REQUIRED","Customer authentication is required.");}}